+++ b/src/main/java/com/yottastudios/ns/collabspace/space/manager/query/SpaceChangeRecordQueryManager.java
@@ -0,0 +1,128 @@
+package com.yottastudios.ns.collabspace.space.manager.query;
+
+import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
+import com.baomidou.mybatisplus.core.metadata.IPage;
+import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
+import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
+import com.yottastudios.ns.collabspace.space.entity.SpaceChangeRecordEntity;
+import com.yottastudios.ns.collabspace.space.enums.SpaceChangeActionEnum;
+import com.yottastudios.ns.collabspace.space.enums.SpaceChangeTypeEnum;
+import com.yottastudios.ns.collabspace.space.service.ISpaceChangeRecordService;
+import com.yottastudios.ns.collabspace.space.vo.SpaceChangeRecordVo;
+import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
+import com.yottastudios.ns.collabspace.shared.util.page.PageHelper;
+import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
+import jakarta.annotation.Resource;
+import org.apache.commons.collections4.CollectionUtils;
+import org.springframework.stereotype.Component;
+
+import java.util.Collections;
+import java.util.List;
+import java.util.Map;
+import java.util.Set;
+import java.util.stream.Collectors;
+import java.util.stream.Stream;
+
+@Component
+public class SpaceChangeRecordQueryManager {
+
+    @Resource
+    private ISpaceChangeRecordService spaceChangeRecordService;
+
+    @Resource
+    private IApitableGrpcClientService apitableGrpcClientService;
+
+    /**
+     * 分页查询变更记录
+     */
+    public PageInfo<SpaceChangeRecordVo> page(String spaceId, Integer type, int pageNum, int pageSize) {
+        Page<SpaceChangeRecordEntity> page = new Page<>(pageNum, pageSize);
+
+        LambdaQueryWrapper<SpaceChangeRecordEntity> wrapper = new LambdaQueryWrapper<>();
+        wrapper.eq(SpaceChangeRecordEntity::getSpaceId, spaceId);
+        if (type != null) {
+            wrapper.eq(SpaceChangeRecordEntity::getType, type);
+        }
+        wrapper.orderByDesc(SpaceChangeRecordEntity::getCreatedAt);
+
+        IPage<SpaceChangeRecordEntity> result = spaceChangeRecordService.page(page, wrapper);
+
+        if (CollectionUtils.isEmpty(result.getRecords())) {
+            return PageHelper.build(result.getCurrent(), result.getSize(), result.getTotal(), Collections.emptyList());
+        }
+
+        // 批量查询用户昵称，避免 N+1
+        Set<Long> userIds = result.getRecords().stream()
+                .flatMap(r -> Stream.of(r.getOperatorId(), r.getTargetUserId()))
+                .collect(Collectors.toSet());
+        Map<Long, String> userNameMap = getUserNameMap(userIds);
+
+        List<SpaceChangeRecordVo> voList = result.getRecords().stream()
+                .map(entity -> toVo(entity, userNameMap))
+                .toList();
+
+        return PageHelper.build(result.getCurrent(), result.getSize(), result.getTotal(), voList);
+    }
+
+    private SpaceChangeRecordVo toVo(SpaceChangeRecordEntity entity, Map<Long, String> userNameMap) {
+        String operatorName = userNameMap.getOrDefault(entity.getOperatorId(), "未知用户");
+        String targetUserName = userNameMap.getOrDefault(entity.getTargetUserId(), "未知用户");
+        String description = buildDescription(entity, operatorName, targetUserName);
+
+        return SpaceChangeRecordVo.builder()
+                .id(entity.getId())
+                .type(entity.getType())
+                .action(entity.getAction())
+                .operatorName(operatorName)
+                .targetUserName(targetUserName)
+                .description(description)
+                .createdAt(entity.getCreatedAt())
+                .build();
+    }
+
+    private String buildDescription(SpaceChangeRecordEntity entity, String operatorName, String targetUserName) {
+        int type = entity.getType();
+        String action = entity.getAction();
+
+        if (type == SpaceChangeTypeEnum.MEMBER.getValue()) {
+            if (SpaceChangeActionEnum.ADD.getValue().equals(action)) {
+                return operatorName + " 将 " + targetUserName + " 添加至空间站";
+            } else {
+                return operatorName + " 将 " + targetUserName + " 移出空间站";
+            }
+        }
+
+        // 子管理员变更
+        String resourceName = getResourceName(entity.getDetail());
+        if (SpaceChangeActionEnum.ADD.getValue().equals(action)) {
+            return operatorName + " 将 " + targetUserName + " 添加为 " + resourceName;
+        } else {
+            return operatorName + " 移除" + targetUserName + "的" + resourceName + "权限";
+        }
+    }
+
+    private String getResourceName(Map<String, Object> detail) {
+        if (detail == null || !detail.containsKey("resourceCode")) {
+            return "未知权限";
+        }
+        String code = String.valueOf(detail.get("resourceCode"));
+        return switch (code) {
+            case "MANAGE_MEMBER" -> "成员管理员";
+            case "MANAGE_WORKBENCH" -> "文件管理员";
+            default -> code;
+        };
+    }
+
+    private Map<Long, String> getUserNameMap(Set<Long> userIds) {
+        if (CollectionUtils.isEmpty(userIds)) {
+            return Collections.emptyMap();
+        }
+        List<UserSimpleInfoVo> users = apitableGrpcClientService.getUserByIds(userIds.stream().toList());
+        if (CollectionUtils.isEmpty(users)) {
+            return Collections.emptyMap();
+        }
+        return users.stream()
+                .collect(Collectors.toMap(UserSimpleInfoVo::getId, UserSimpleInfoVo::getNickName,
+                        (a, b) -> a));
+    }
+}
