+package com.yottastudios.ns.collabspace.space.manager.update;
+
+import com.yottastudios.ns.collabspace.space.entity.SpaceChangeRecordEntity;
+import com.yottastudios.ns.collabspace.space.enums.SpaceChangeActionEnum;
+import com.yottastudios.ns.collabspace.space.enums.SpaceChangeTypeEnum;
+import com.yottastudios.ns.collabspace.space.service.ISpaceChangeRecordService;
+import jakarta.annotation.Resource;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.stereotype.Component;
+
+import java.util.ArrayList;
+import java.util.List;
+import java.util.Map;
+
+@Component
+@Slf4j
+public class SpaceChangeRecordUpdateManager {
+
+    @Resource
+    private ISpaceChangeRecordService spaceChangeRecordService;
+
+    /**
+     * 记录子管理员权限变更（增量拆分：每个权限一条记录）
+     *
+     * @param spaceId       空间站ID
+     * @param operatorId    操作人ID（主管理员）
+     * @param targetUserId  被操作人ID
+     * @param addedCodes    新增的权限码列表
+     * @param removedCodes  移除的权限码列表
+     */
+    public void recordSubAdminChange(String spaceId, Long operatorId, Long targetUserId,
+                                     List<String> addedCodes, List<String> removedCodes) {
+        List<SpaceChangeRecordEntity> records = new ArrayList<>();
+        for (String code : addedCodes) {
+            records.add(buildRecord(spaceId, SpaceChangeTypeEnum.SUB_ADMIN,
+                    SpaceChangeActionEnum.ADD, operatorId, targetUserId,
+                    Map.of("resourceCode", code)));
+        }
+        for (String code : removedCodes) {
+            records.add(buildRecord(spaceId, SpaceChangeTypeEnum.SUB_ADMIN,
+                    SpaceChangeActionEnum.REMOVE, operatorId, targetUserId,
+                    Map.of("resourceCode", code)));
+        }
+        if (!records.isEmpty()) {
+            spaceChangeRecordService.saveBatch(records);
+            log.info("[lbl][2101-变更记录][ChangeRecord][CREATE] 子管理员权限变更, spaceId={}, operatorId={}, targetUserId={}, added={}, removed={}",
+                    spaceId, operatorId, targetUserId, addedCodes, removedCodes);
+        }
+    }
+
+    /**
+     * 记录成员变更
+     *
+     * @param spaceId      空间站ID
+     * @param operatorId   操作人ID（主管理员）
+     * @param targetUserId 被操作人ID
+     * @param join         true=加入，false=移出
+     */
+    public void recordMemberChange(String spaceId, Long operatorId, Long targetUserId, boolean join) {
+        SpaceChangeActionEnum action = join ? SpaceChangeActionEnum.ADD : SpaceChangeActionEnum.REMOVE;
+        SpaceChangeRecordEntity record = buildRecord(spaceId, SpaceChangeTypeEnum.MEMBER,
+                action, operatorId, targetUserId, null);
+        spaceChangeRecordService.save(record);
+        log.info("[lbl][2101-变更记录][ChangeRecord][CREATE] 成员变更, spaceId={}, operatorId={}, targetUserId={}, action={}",
+                spaceId, operatorId, targetUserId, action.getValue());
+    }
+
+    private SpaceChangeRecordEntity buildRecord(String spaceId, SpaceChangeTypeEnum type,
+                                                 SpaceChangeActionEnum action, Long operatorId,
+                                                 Long targetUserId, Map<String, Object> detail) {
+        return SpaceChangeRecordEntity.builder()
+                .spaceId(spaceId)
+                .type(type.getValue())
+                .action(action.getValue())
+                .operatorId(operatorId)
+                .targetUserId(targetUserId)
+                .detail(detail)
+                .build();
+    }
+}
