+                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
+                    continue;
+                }
+
+                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
+                        .nodeId(newSpaceNodeEntity.getId())
+                        .snapshotId(newSnapshotFileId)
+                        .snapshotName(snapshot.getSnapshotName())
+                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
+                        .operatorId(userId)
+                        .build();
+                versionSnapshotService.save(newSnapshot);
+
+                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
+                        .appSpaceNodeId(newSnapshotFileId)
+                        .name(snapshot.getSnapshotName())
+                        .type(newSpaceNodeEntity.getType())
+                        .description("")
+                        .spaceId(targetSpaceId)
+                        .createdBy(userId)
+                        .updatedBy(userId)
+                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
+                        .build();
+                spaceNodeService.save(snapshotSpaceNode);
+
+                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied, originalSnapshotId={}, newSnapshotId={}",
+                        snapshot.getSnapshotId(), newSnapshotFileId);
+            } catch (Exception e) {
+                log.error("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed, originalNodeId={}, snapshotId={}, error={}",
+                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
+            }
+        }
+    }
 }
