565→+        log.info("[lbl][2087-消息推送][Feedback][{}] MM消息同步, postId={}, nickName={}, messageId={}, fileCount={}",
566→+                action.toUpperCase(), ro.getPostId(), ro.getFeedbackNickName(), ro.getMessageId(),
567→+                ro.getFiles() != null ? ro.getFiles().size() : 0);
568→+
569→+        switch (action) {
570→+            case "create" -> mmHandleCreate(ro);
571→+            case "update" -> mmHandleUpdate(ro);
572→+            case "delete" -> mmHandleDelete(ro);
573→+            default -> log.warn("[lbl][2087-消息推送][Feedback] 未知action={}, postId={}", action, ro.getPostId());
574→+        }
