577→+    private void mmHandleCreate(MmFeedbackWebhookRo ro) {
578→+        List<String> attachmentUrls = downloadMmFiles(ro);
579→+        LocalDateTime feedbackTime = parseFeedbackTime(ro.getFeedbackTime());
580→+        String extraInfo = buildExtraInfo(ro.getMessageId());
581→+
582→+        FeedbackEntity entity = FeedbackEntity.builder()
583→+                .postId(ro.getPostId())
584→+                .userId(ro.getFeedbackNickName())
585→+                .userName(ro.getFeedbackNickName())
586→+                .feedbackTime(feedbackTime)
587→+                .content(ro.getContent())
588→+                .attachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls))
589→+                .extraInfo(extraInfo)
590→+                .source(FeedbackSource.MM.getCode())
591→+                .status(FeedbackStatus.UNPROCESSED.getCode())
592→+                .build();
593→+
594→+        feedbackMapper.insert(entity);
595→+        log.info("[lbl][2087-消息推送][Feedback][CREATE] 写入成功, id={}, postId={}, nickName={}",
596→+                entity.getId(), ro.getPostId(), ro.getFeedbackNickName());
597→+    }
