603→+            mmHandleCreate(ro);
604→+            return;
605→+        }
606→+
607→+        List<String> attachmentUrls = downloadMmFiles(ro);
608→+        existing.setContent(ro.getContent());
609→+        existing.setAttachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls));
610→+        existing.setFeedbackTime(parseFeedbackTime(ro.getFeedbackTime()));
611→+        existing.setExtraInfo(buildExtraInfo(ro.getMessageId()));
612→+        feedbackMapper.updateById(existing);
613→+        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新成功, id={}, postId={}", existing.getId(), ro.getPostId());
614→+    }
