664→+    @Override
665→+    public IPage<FeedbackVo> listFeedback(FeedbackListRo ro) {
666→+        int pageNum = ro.getPageNum() != null ? ro.getPageNum() : 1;
667→+        int pageSize = ro.getPageSize() != null ? ro.getPageSize() : 20;
668→+
669→+        LambdaQueryWrapper<FeedbackEntity> wrapper = new LambdaQueryWrapper<>();
670→+        wrapper.eq(FeedbackEntity::getIsDeleted, 0);
671→+
672→+        if (ro.getStatus() != null) {
673→+            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
674→+        }
675→+        if (StrUtil.isNotBlank(ro.getDocType())) {
676→+            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
677→+        }
678→+        if (StrUtil.isNotBlank(ro.getFeedbackType())) {
679→+            wrapper.eq(FeedbackEntity::getFeedbackType, ro.getFeedbackType());
680→+        }
681→+        if (StrUtil.isNotBlank(ro.getStartDate())) {
682→+            try {
683→+                LocalDate startDate = LocalDate.parse(ro.getStartDate(), DateTimeFormatter.ISO_LOCAL_DATE);
684→+                wrapper.ge(FeedbackEntity::getFeedbackTime, startDate.atStartOfDay());
685→+            } catch (java.time.format.DateTimeParseException e) {
686→+                throw new BusinessException("开始日期格式错误，应为yyyy-MM-dd");
687→+            }
688→+        }
689→+        if (StrUtil.isNotBlank(ro.getEndDate())) {
690→+            try {
691→+                LocalDate endDate = LocalDate.parse(ro.getEndDate(), DateTimeFormatter.ISO_LOCAL_DATE);
692→+                wrapper.le(FeedbackEntity::getFeedbackTime, endDate.plusDays(1).atStartOfDay());
693→+            } catch (java.time.format.DateTimeParseException e) {
694→+                throw new BusinessException("结束日期格式错误，应为yyyy-MM-dd");
695→+            }
696→+        }
697→+        if (StrUtil.isNotBlank(ro.getKeyword())) {
698→+            wrapper.like(FeedbackEntity::getContent, ro.getKeyword());
699→+        }
700→+
701→+        wrapper.orderByDesc(FeedbackEntity::getFeedbackTime);
702→+
703→+        IPage<FeedbackEntity> page = feedbackMapper.selectPage(new Page<>(pageNum, pageSize), wrapper);
704→+
705→+        return page.convert(this::toVo);
706→+    }
