711→+        FeedbackEntity entity = feedbackMapper.selectById(ro.getFeedbackId());
712→+        if (entity == null) {
713→+            log.warn("[lbl][2087-消息推送][Feedback][UPDATE] 反馈记录不存在, id={}", ro.getFeedbackId());
714→+            throw new BusinessException("反馈记录不存在");
715→+        }
716→+        entity.setStatus(ro.getStatus());
717→+        feedbackMapper.updateById(entity);
718→+        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新反馈状态成功, id={}, status={}", ro.getFeedbackId(), ro.getStatus());
719→+    }
720→+
721→+    /**
722→+     * 上传前端附件到MinIO
723→+     */
724→+    private List<String> uploadFilesToMinio(List<MultipartFile> files) {
725→+        List<String> urls = new ArrayList<>();
726→+        if (files == null || files.isEmpty()) {
727→+            return urls;
728→+        }
729→+        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
730→+        for (MultipartFile file : files) {
731→+            try {
732→+                String keyPath = "feedback/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
733→+                        + "/" + UUID.randomUUID() + "_" + file.getOriginalFilename();
734→+                ossTemplate.upload(bucketName, file.getInputStream(), keyPath);
735→+                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
736→+                urls.add(url);
737→+            } catch (IOException e) {
738→+                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] 附件上传MinIO失败, fileName={}, error={}", file.getOriginalFilename(), e.getMessage(), e);
739→+            }
740→+        }
741→+        return urls;
742→+    }
743→+
744→+    /**
745→+     * 从MM下载附件并上传到MinIO
746→+     */
747→+    private List<String> downloadMmFilesAndUpload(List<String> fileIds) {
748→+        List<String> urls = new ArrayList<>();
749→+        if (fileIds == null || fileIds.isEmpty()) {
750→+            return urls;
751→+        }
752→+        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
753→+        String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();
754→+
755→+        for (String fileId : fileIds) {
756→+            try {
757→+                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] 调用MM Feign下载附件, fileId={}", fileId);
758→+                byte[] fileData = mattermostMessageFeign.downloadFile(authToken, fileId);
759→+                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] MM附件下载完成, fileId={}, fileSize={}bytes", fileId, fileData.length);
760→+                String keyPath = "feedback/mm/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
761→+                        + "/" + UUID.randomUUID() + "_" + fileId;
762→+                ossTemplate.upload(bucketName, new ByteArrayInputStream(fileData), keyPath);
763→+                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
764→+                urls.add(url);
765→+                log.info("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件上传MinIO成功, fileId={}, keyPath={}", fileId, keyPath);
766→+            } catch (Exception e) {
767→+                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件下载上传失败, fileId={}, error={}", fileId, e.getMessage(), e);
768→+            }
769→+        }
770→+        return urls;
771→+    }
