774→+        FeedbackVo vo = new FeedbackVo();
775→+        vo.setId(entity.getId());
776→+        vo.setUserId(entity.getUserId());
777→+        vo.setUserName(entity.getUserName());
778→+        vo.setFeedbackTime(entity.getFeedbackTime());
779→+        vo.setDocType(entity.getDocType());
780→+        vo.setFeedbackType(entity.getFeedbackType());
781→+        vo.setRelatedLink(entity.getRelatedLink());
782→+        vo.setContent(entity.getContent());
783→+        vo.setAttachments(StrUtil.isNotBlank(entity.getAttachments())
784→+                ? JSONUtil.toList(entity.getAttachments(), String.class)
785→+                : List.of());
786→+        vo.setExtraInfo(entity.getExtraInfo());
787→+        vo.setSource(entity.getSource());
788→+        vo.setStatus(entity.getStatus());
789→+        return vo;
790→+    }
