import java.util.List;

@Slf4j
@RestController
@Tag(name = "ManageBack Space")
@ApiResource(path = "/management/space")
public class ManagementSpaceController {

    @Resource
    private ManagementSpaceQueryManger managementSpaceQueryManger;
    @Resource
    private ManagementSpaceUpdateManger managementSpaceUpdateManger;
    @Resource
    private SpaceChangeRecordQueryManager spaceChangeRecordQueryManager;
    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;
    @Value("#{'${user-auth.super-board-manager-list}'.split(',')}")
    private List<String> allowUserList;

    @GetResource(path = "/list/get",requiredPermission = false)
    @Operation(summary = "List All Space")
    public ResponseData<List<ManagementSpaceVo>> spaceList() {

        Long userId = SessionContext.getUserId();
        List<ManagementSpaceVo> spaces = managementSpaceQueryManger.getSpaceList(userId);
        return ResponseData.success(spaces);

    }

    @PostResource(path = "/add",requiredPermission = false)
    @Operation(summary = "Add Space")
    public ResponseData<Void> addSpace(@RequestBody @Valid final AddManagementSpaceRo ro) {
        Long userId = SessionContext.getUserId();
        managementSpaceUpdateManger.addSpace(ro, userId);
        return ResponseData.success();
    }

    @PostResource(path = "/remove",requiredPermission = false)
    @Operation(summary = "Remove Space")
    public ResponseData<Void> removeSpace(@RequestBody @Valid final RemoveManagementSpaceRo ro) {
        Long userId = SessionContext.getUserId();
        managementSpaceUpdateManger.removeSpace(ro,userId);
        return ResponseData.success();
    }

    @GetResource(path = "/changeRecord/page", requiredPermission = false)
    @Operation(summary = "查询空间站变更记录（产品后台）")
    public ResponseData<PageInfo<SpaceChangeRecordVo>> changeRecordPage(SpaceChangeRecordPageRo ro) {
        Long userId = SessionContext.getUserId();
        UserSimpleInfoVo userSimpleInfoVo = apitableGrpcClientService.getUserById(userId);
        if (userSimpleInfoVo == null || !allowUserList.contains(userSimpleInfoVo.getNickName())) {
            log.warn("[lbl][2101-变更记录][ChangeRecord][DENIED] 非超管访问变更记录, userId={}", userId);
            throw new BusinessException(403, "No Authorization");
        }
        PageInfo<SpaceChangeRecordVo> result = spaceChangeRecordQueryManager.page(
                ro.getSpaceId(), ro.getType(), ro.getPageNum(), ro.getPageSize());
        return ResponseData.success(result);
    }


}

