 96→    abstract static class TreeNodeMixin<T extends RelIdProvider> {
 97→        @JsonProperty("children")
 98→        @JsonDeserialize(contentAs = TreeNode.class)
 99→        abstract List<TreeNode<T>> getChildren();
100→
101→        @JsonProperty("children")
102→        abstract void setChildren(List<TreeNode<T>> children);
103→    }
104→
105→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
106→    public void handle(Message message, Channel channel) throws IOException {
107→        String body = new String(message.getBody());
108→        log.info("Received space node migration task message: {}", body);
109→
110→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
111→        String taskId = messageDto.getTaskId();
112→
113→        try {
114→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
115→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
116→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
117→            spaceNodeMigrationTaskService.updateById(task);
118→
119→            executeTask(task);
120→
121→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
122→            spaceNodeMigrationTaskService.updateById(task);
123→
124→        } catch (Exception e) {
125→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
126→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
127→            if (task != null) {
128→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
129→                task.setErrorMessage(e.getMessage());
130→                spaceNodeMigrationTaskService.updateById(task);
131→            }
132→        } finally {
133→            // 先不考虑重试
134→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
135→            channel.basicAck(deliveryTag, false);
136→        }
137→    }
138→
139→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
140→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
141→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
142→        Long userId = user.getId();
143→        // 鉴权
144→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
145→            throw new BusinessException(AuthException.UNAUTHORIZED);
146→        }
147→
148→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
149→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
150→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
151→
152→        log.info("executeTask: taskId={}, treeSize={}, type: {}, appRels: {}", task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getSourceSpaceAppRels());
153→
154→        MigrationConfig migrationConfig = MigrationConfig.builder()
155→                .email(task.getEmail())
156→                .sourceSpaceAppRels(sourceSpaceAppRels)
157→                .build();
158→        
159→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
160→                spaceNodeTree, 
161→                task.getTargetSpaceId(),
162→                task.getSourceSpaceId(),
163→                migrationType, 
164→                migrationConfig
165→        );
166→        
167→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
168→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
169→                overallResult.getNodeIdMapping().size());
170→
171→        // 迁移中遇到错误抛异常并终止迁移
172→        if (overallResult.getErrorMessage() != null) {
173→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
174→            throw new BusinessException(overallResult.getErrorMessage());
175→        }
176→
177→        // 迁移后的节点重新构建成树并入库
178→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId,
179→                task.getSourceSpaceId(), migrationType, migrationConfig);
180→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
181→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
182→            log.info("[lbl][2122-文件迁移][Migration][DELETE] 移动模式, 开始清理源文件及快照, taskId={}, sourceSpaceId={}, nodeCount={}",
183→                    task.getTaskId(), task.getSourceSpaceId(), spaceNodeTree.size());
184→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
185→                // 清理源文件的版本快照
186→                versionSnapshotService.disableByNodeId(treeNode.getRelId());
187→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
188→            }
189→        }
190→    }
191→
192→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping,
193→                                  Long userId, String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
194→        if (originalTree == null || originalTree.isEmpty()) {
195→            log.info("No tree nodes to save for space: {}", spaceId);
196→            return;
197→        }
198→
199→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
200→
201→        for (TreeNode<SpaceNodeVo> node : originalTree) {
202→            saveNodeAndChildren(node, spaceId, nodeIdMapping, ROOT_PARENT_ID, userId,
203→                    sourceSpaceId, migrationType, migrationConfig);
204→        }
205→
206→        log.info("Completed saving new node tree for space: {}", spaceId);
207→    }
208→
209→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
210→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
211→            return name;
212→        }
213→        int count = 1;
214→        while (true) {
215→            String candidate = name + "(" + count + ")";
216→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
217→                return candidate;
218→            }
219→            count++;
220→        }
221→    }
222→
223→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
224→                                      Long parentId, Long userId, String sourceSpaceId,
225→                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
226→        SpaceNodeVo spaceNodeVo = node.getData();
227→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
228→        String newNodeId = nodeIdMapping.get(oldNodeId);
229→
230→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
231→            newNodeId = "";
232→        }
233→
234→        if (newNodeId == null) {
235→            log.error("No mapping found for node: {}", oldNodeId);
236→            return;
237→        }
238→
239→        String originalName = spaceNodeVo.getName();
240→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
241→                ? resolveUniqueName(spaceId, originalName, parentId)
242→                : originalName;
243→        if (!name.equals(originalName)) {
244→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
245→                            "parentId: {}",
246→                    originalName,
247→                    name, spaceId, parentId);
248→        }
249→
250→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
251→                .appSpaceNodeId(newNodeId)
252→                .name(name)
253→                .type(spaceNodeVo.getType())
254→                .description(spaceNodeVo.getDescription())
255→                .spaceId(spaceId)
256→                .createdBy(userId)
257→                .updatedBy(userId)
258→                .build();
259→
260→        spaceNodeService.save(spaceNodeEntity);
261→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
262→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
263→
264→        // 复制文件关联的版本快照
265→        copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);
266→
267→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
268→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
269→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
270→                        sourceSpaceId, migrationType, migrationConfig);
271→            }
272→        }
