import com.yottastudios.ns.collabspace.space.vo.SpaceAppRelVo;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import com.yottastudios.ns.collabspace.workspace.dto.MigrationConfig;
import com.yottastudios.ns.collabspace.workspace.dto.SpaceNodeMigrationResult;
import com.yottastudios.ns.collabspace.workspace.dto.SpaceNodeMigrationMessage;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeMigrationTaskEntity;
import com.yottastudios.ns.collabspace.workspace.enums.MigrationTypeEnum;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeMigrationException;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeMigrationTaskStatusEnum;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeUpdateManager;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeMigrationTaskService;
import com.yottastudios.ns.collabspace.workspace.service.thirdparty.ThirdAppMigrationChain;
import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import com.yottastudios.ns.collabspace.base.service.RelIdProvider;
import com.yottastudios.ns.collabspace.base.manager.TreeNodeTemplate;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import com.yottastudios.ns.collabspace.workspace.entity.CollabspaceVersionSnapshotEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeSnapshotEnum;
import com.yottastudios.ns.collabspace.workspace.enums.VersionSnapshotStatusEnum;
import com.yottastudios.ns.collabspace.workspace.service.IVersionSnapshotService;
import com.yottastudios.ns.collabspace.space.service.ISpaceAppRelService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.stereotype.Component;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Objects;

import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;
import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.SPACE_NODE_MIGRATION_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class SpaceNodeMigrationConsumer {

    @Resource
    private ISpaceNodeMigrationTaskService spaceNodeMigrationTaskService;

    @Resource
    private ObjectMapper objectMapper;

    @Resource
    private ThirdAppMigrationChain appMigrationChain;

    @Resource
    private TreeNodeTemplate treeNodeTemplate;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private SpaceQueryManager spaceQueryManager;

    @Resource
    private SpaceNodeUpdateManager spaceNodeUpdateManager;

    @Resource
    private SpaceNodeQueryManager spaceNodeQueryManager;

    @Resource
    private IVersionSnapshotService versionSnapshotService;

    @Resource
    private ISpaceAppRelService spaceAppRelService;

    abstract static class TreeNodeMixin<T extends RelIdProvider> {
        @JsonProperty("children")
        @JsonDeserialize(contentAs = TreeNode.class)
        abstract List<TreeNode<T>> getChildren();

        @JsonProperty("children")
        abstract void setChildren(List<TreeNode<T>> children);
    }

    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        String body = new String(message.getBody());
        log.info("Received space node migration task message: {}", body);

        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
        String taskId = messageDto.getTaskId();

        try {
            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
            spaceNodeMigrationTaskService.updateById(task);

            executeTask(task);

            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
            spaceNodeMigrationTaskService.updateById(task);

        } catch (Exception e) {
            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
            if (task != null) {
                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
                task.setErrorMessage(e.getMessage());
                spaceNodeMigrationTaskService.updateById(task);
            }
        } finally {
            // 先不考虑重试
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }

    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
        Long userId = user.getId();
        // 鉴权
        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
            throw new BusinessException(AuthException.UNAUTHORIZED);
        }

        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());

        log.info("executeTask: taskId={}, treeSize={}, type: {}, appRels: {}", task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getSourceSpaceAppRels());

        MigrationConfig migrationConfig = MigrationConfig.builder()
                .email(task.getEmail())
                .sourceSpaceAppRels(sourceSpaceAppRels)
                .build();

        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
                spaceNodeTree, 
                task.getTargetSpaceId(),
                task.getSourceSpaceId(),
                migrationType, 
                migrationConfig
        );

        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
                overallResult.getNodeIdMapping().size());

        // 迁移中遇到错误抛异常并终止迁移
        if (overallResult.getErrorMessage() != null) {
            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
            throw new BusinessException(overallResult.getErrorMessage());
        }

        // 迁移后的节点重新构建成树并入库
        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId,
                task.getSourceSpaceId(), migrationType, migrationConfig);
        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
            log.info("[lbl][2122-文件迁移][Migration][DELETE] 移动模式, 开始清理源文件及快照, taskId={}, sourceSpaceId={}, nodeCount={}",
                    task.getTaskId(), task.getSourceSpaceId(), spaceNodeTree.size());
            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
                // 清理源文件的版本快照
                versionSnapshotService.disableByNodeId(treeNode.getRelId());
                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
            }
        }
    }

    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping,
                                  Long userId, String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
        if (originalTree == null || originalTree.isEmpty()) {
            log.info("No tree nodes to save for space: {}", spaceId);
            return;
        }

        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());

        for (TreeNode<SpaceNodeVo> node : originalTree) {
            saveNodeAndChildren(node, spaceId, nodeIdMapping, ROOT_PARENT_ID, userId,
                    sourceSpaceId, migrationType, migrationConfig);
        }

        log.info("Completed saving new node tree for space: {}", spaceId);
    }

    private String resolveUniqueName(String spaceId, String name, Long parentId) {
        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
            return name;
        }
        int count = 1;
        while (true) {
            String candidate = name + "(" + count + ")";
            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
                return candidate;
            }
            count++;
        }
    }

    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
                                      Long parentId, Long userId, String sourceSpaceId,
                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
        SpaceNodeVo spaceNodeVo = node.getData();
        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
        String newNodeId = nodeIdMapping.get(oldNodeId);

        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            newNodeId = "";
        }

        if (newNodeId == null) {
            log.error("No mapping found for node: {}", oldNodeId);
            return;
        }

        String originalName = spaceNodeVo.getName();
        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
                ? resolveUniqueName(spaceId, originalName, parentId)
                : originalName;
        if (!name.equals(originalName)) {
            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
                            "parentId: {}",
                    originalName,
                    name, spaceId, parentId);
        }

        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
                .appSpaceNodeId(newNodeId)
                .name(name)
                .type(spaceNodeVo.getType())
                .description(spaceNodeVo.getDescription())
                .spaceId(spaceId)
                .createdBy(userId)
                .updatedBy(userId)
                .build();

        spaceNodeService.save(spaceNodeEntity);
        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());

        // 复制文件关联的版本快照
        copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);

        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
                        sourceSpaceId, migrationType, migrationConfig);
            }
        }
    }

    /**
     * 迁移文件时，复制其关联的历史版本快照
     */
    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
                                       String targetSpaceId, String sourceSpaceId,
                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig,
                                       Long userId) {
        // 文件夹没有版本快照
        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            return;
        }

        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
        if (snapshots.isEmpty()) {
            return;
        }

        log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: originalNodeId={}, newNodeId={}, snapshotCount={}",
                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());

        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
            try {
                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
                snapshotNodeVo.setName(snapshot.getSnapshotName());

                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
                snapshotTreeNode.setData(snapshotNodeVo);

                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
                snapshotTree.add(snapshotTreeNode);

                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);

                if (result.getErrorMessage() != null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot file, originalNodeId={}, snapshotId={}, error={}",
                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
                    continue;
                }

                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
                if (newSnapshotFileId == null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
                    continue;
                }

                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
                        .nodeId(newSpaceNodeEntity.getId())
                        .snapshotId(newSnapshotFileId)
                        .snapshotName(snapshot.getSnapshotName())
                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
                        .operatorId(userId)
                        .build();
                versionSnapshotService.save(newSnapshot);

                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
                        .appSpaceNodeId(newSnapshotFileId)
                        .name(snapshot.getSnapshotName())
                        .type(newSpaceNodeEntity.getType())
                        .description("")
                        .spaceId(targetSpaceId)
                        .createdBy(userId)
                        .updatedBy(userId)
                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
                        .build();
                spaceNodeService.save(snapshotSpaceNode);

                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied snapshot, originalSnapshotId={}, newSnapshotId={}, newNodeId={}",
                        snapshot.getSnapshotId(), newSnapshotFileId, newSpaceNodeEntity.getId());

            } catch (Exception e) {
                log.error("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot, originalNodeId={}, snapshotId={}, error={}",
                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
            }
        }
    }

    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
        ObjectMapper mapper = objectMapper.copy();
        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
        SimpleModule module = new SimpleModule();
        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
        mapper.registerModule(module);
        JavaType treeNodeType =
                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
        JavaType listType =
                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
        return mapper.readValue(json, listType);
    }

}

