164→    public String acceptMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId,
165→                                      String sourceSpaceId, List<SpaceAppRelVo> appRels, Integer migrationType, Boolean isRemained) {
166→        if (CollectionUtils.isEmpty(spaceNodeTree) || StringUtils.isBlank(targetSpaceId) || StringUtils.isBlank(email) || StringUtils.isBlank(sourceSpaceId)) {
167→            log.error("email={}, targetSpaceId={}, sourceSpaceId={}", email, targetSpaceId, sourceSpaceId);
168→            throw new BusinessException("acceptMigrationTask: empty or invalid arguments");
169→        }
170→
171→        String taskId = sourceSpaceId + "-" + targetSpaceId + "-" + System.currentTimeMillis();
172→
173→        SpaceNodeMigrationTaskEntity spaceNodeMigrationTaskEntity = SpaceNodeMigrationTaskEntity.builder()
174→                .taskId(taskId)
175→                .sourceSpaceId(sourceSpaceId)
176→                .targetSpaceId(targetSpaceId)
177→                .email(email)
178→                .originTree(JSONUtil.toJsonStr(spaceNodeTree))
179→                .sourceSpaceAppRels(JSONUtil.toJsonStr(appRels))
180→                .status(SpaceNodeMigrationTaskStatusEnum.PENDING.getValue())
181→                .type(migrationType)
182→                .isRemained(isRemained)
183→                .build();
184→        spaceNodeMigrationTaskService.save(spaceNodeMigrationTaskEntity);
185→
186→        SpaceNodeMigrationMessage message = SpaceNodeMigrationMessage.builder()
187→                .taskId(taskId)
188→                .build();
189→        rabbitMqSender.directSend(SPACE_NODE_MIGRATION_EXCHANGE, SPACE_NODE_MIGRATION_KEY, JSONUtil.toJsonStr(message));
190→
191→        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}",
192→                taskId, email, targetSpaceId, sourceSpaceId, spaceNodeTree.size());
193→
194→        return taskId;
195→    }
