386→        for (TreeNode<SpaceNodeVo> node : originalTree) {
387→            Long parentId = ROOT_PARENT_ID;
388→            if (spaceId.equals(node.getData().getSpaceId())) {
389→                // 同空间站复制在原父节点下
390→                // todo 优化
391→                parentId = node.getParentId();
392→            }
393→            saveNodeAndChildren(node, spaceId, nodeIdMapping, parentId, userId,
394→                    sourceSpaceId, migrationType, migrationConfig);
395→        }
396→
397→        log.info("Completed saving new node tree for space: {}", spaceId);
