400→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
401→                                     Long parentId, Long userId, String sourceSpaceId,
402→                                     MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
403→        SpaceNodeVo spaceNodeVo = node.getData();
404→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
405→        String newNodeId = nodeIdMapping.get(oldNodeId);
406→
407→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
408→            newNodeId = "";
409→        }
410→
411→        if (newNodeId == null) {
412→            log.error("No mapping found for node: {}", oldNodeId);
413→            return;
414→        }
415→
416→        // todo:这里的序号没有考虑并发问题，如有需使用分布式锁
417→        Integer count = nodeInstancesManager.getCountByOriginId(node.getData().getId());
418→        String name = node.getData().getName() +  "的副本" ;
419→        if (count > 0){
420→            name = name + "(" + count + ")";
421→        }
422→
423→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
424→                .appSpaceNodeId(newNodeId)
425→                .name(name)
426→                .type(spaceNodeVo.getType())
427→                .description(spaceNodeVo.getDescription())
428→                .spaceId(spaceId)
429→                .createdBy(userId)
430→                .updatedBy(userId)
431→                .build();
432→
433→        spaceNodeService.save(spaceNodeEntity);
434→
435→        // 补充副本关系
436→        nodeInstancesManager.createInstance(node.getData().getId(), spaceNodeEntity.getId(), 0);
437→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
438→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
439→
440→        // 复制文件关联的版本快照
441→        copyVersionSnapshots(node.getData().getId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);
442→
443→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
444→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
445→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
446→                        sourceSpaceId, migrationType, migrationConfig);
447→            }
448→        }
449→    }
