500→    /**
501→     * 迁移文件时，复制其关联的历史版本快照
502→     */
503→    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
504→                                       String targetSpaceId, String sourceSpaceId,
505→                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig,
506→                                       Long userId) {
507→        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
508→            return;
509→        }
510→
511→        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
512→                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
513→        if (snapshots.isEmpty()) {
514→            return;
515→        }
516→
517→        log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: originalNodeId={}, newNodeId={}, snapshotCount={}",
518→                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());
519→
520→        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
521→            try {
522→                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
523→                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
524→                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
525→                snapshotNodeVo.setName(snapshot.getSnapshotName());
526→
527→                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
528→                snapshotTreeNode.setData(snapshotNodeVo);
529→
530→                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
531→                snapshotTree.add(snapshotTreeNode);
532→
533→                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
534→                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);
535→
536→                if (result.getErrorMessage() != null) {
537→                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed, originalNodeId={}, snapshotId={}, error={}",
538→                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
539→                    continue;
540→                }
541→
542→                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
543→                if (newSnapshotFileId == null) {
544→                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
545→                    continue;
546→                }
547→
548→                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
549→                        .nodeId(newSpaceNodeEntity.getId())
550→                        .snapshotId(newSnapshotFileId)
551→                        .snapshotName(snapshot.getSnapshotName())
552→                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
553→                        .operatorId(userId)
554→                        .build();
555→                versionSnapshotService.save(newSnapshot);
556→
557→                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
558→                        .appSpaceNodeId(newSnapshotFileId)
559→                        .name(snapshot.getSnapshotName())
560→                        .type(newSpaceNodeEntity.getType())
561→                        .description("")
562→                        .spaceId(targetSpaceId)
563→                        .createdBy(userId)
564→                        .updatedBy(userId)
565→                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
566→                        .build();
567→                spaceNodeService.save(snapshotSpaceNode);
568→
569→                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied, originalSnapshotId={}, newSnapshotId={}",
