    @Override
    public String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained) {
        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        String email = user.getEmail();
        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
        List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream().map(SpaceAppRelVo::new).toList();

        // 目前每个服务都只会执行一种迁移逻辑, MigrationTypeEnum直接由服务环境判断, mirror服务只执行跨服务器迁移, 其它的都是服务器内迁移
        String taskId;
        if (constProperties.isMirror()) {
            taskId = collabspaceGrpcClientService.createSpaceNodeMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps);
        } else {
            taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained);
        }

        log.info("createMigrationTask: taskId={}, sourceNodeIds={}, targetSpaceId={}, sourceSpaceId={}, userId={}, filteredTreeSize={}",
                taskId, spaceNodeIds, targetSpaceId, sourceSpaceId, userId, spaceNodeTree.size());

        return taskId;
    }

    @Override
    public String createBatchMigrationTask(List<BatchMigrationItem> items,
                                           String targetSpaceId, Long userId, Boolean isRemained) {
        String batchId = "batch-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 6);
        log.info("[lbl][2122-文件迁移][Migration][CREATE] 开始创建批量迁移, batchId={}, targetSpaceId={}, sourceCount={}, isRemained={}",
                batchId, targetSpaceId, items.size(), isRemained);

        // 提前查询用户信息，避免循环内重复 gRPC 调用
        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        String email = user.getEmail();

        for (BatchMigrationItem item : items) {
            String sourceSpaceId = item.getSourceSpaceId();
            List<Long> spaceNodeIds = item.getSpaceNodeIds();

            Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);

            List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
            List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
            List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream()
                    .map(SpaceAppRelVo::new).toList();

            String taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained);

            // 更新子任务的 batchId
            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
            task.setBatchId(batchId);
            spaceNodeMigrationTaskService.updateById(task);

            log.info("[lbl][2122-文件迁移][Migration][CREATE] 批量迁移子任务已创建, batchId={}, taskId={}, sourceSpaceId={}, nodeCount={}",
                    batchId, taskId, sourceSpaceId, spaceNodeIds.size());
        }

        log.info("[lbl][2122-文件迁移][Migration][CREATE] 批量迁移任务创建完成, batchId={}, totalSubTasks={}", batchId, items.size());
        return batchId;
    }

    @Override
    public String acceptMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId,
                                      String sourceSpaceId, List<SpaceAppRelVo> appRels, Integer migrationType, Boolean isRemained) {
        if (CollectionUtils.isEmpty(spaceNodeTree) || StringUtils.isBlank(targetSpaceId) || StringUtils.isBlank(email) || StringUtils.isBlank(sourceSpaceId)) {
            log.error("email={}, targetSpaceId={}, sourceSpaceId={}", email, targetSpaceId, sourceSpaceId);
            throw new BusinessException("acceptMigrationTask: empty or invalid arguments");
        }

        String taskId = sourceSpaceId + "-" + targetSpaceId + "-" + System.currentTimeMillis();

        SpaceNodeMigrationTaskEntity spaceNodeMigrationTaskEntity = SpaceNodeMigrationTaskEntity.builder()
                .taskId(taskId)
                .sourceSpaceId(sourceSpaceId)
                .targetSpaceId(targetSpaceId)
                .email(email)
                .originTree(JSONUtil.toJsonStr(spaceNodeTree))
                .sourceSpaceAppRels(JSONUtil.toJsonStr(appRels))
                .status(SpaceNodeMigrationTaskStatusEnum.PENDING.getValue())
                .type(migrationType)
                .isRemained(isRemained)
                .build();
        spaceNodeMigrationTaskService.save(spaceNodeMigrationTaskEntity);

        SpaceNodeMigrationMessage message = SpaceNodeMigrationMessage.builder()
                .taskId(taskId)
                .build();
        rabbitMqSender.directSend(SPACE_NODE_MIGRATION_EXCHANGE, SPACE_NODE_MIGRATION_KEY, JSONUtil.toJsonStr(message));

        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}",
                taskId, email, targetSpaceId, sourceSpaceId, spaceNodeTree.size());

        return taskId;
    }

    @Override
    public List<CopyFileVo> copyFile(List<Long> spaceNodeIds, Long userId, String sourceSpaceId, String targetSpaceId) {
        List<CopyFileVo> copyFileVoList = new ArrayList<>();
        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(sourceSpaceId);
        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);

        checkCopy(spaceNodeTree, targetSpaceId);

        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(MigrationTypeEnum.INTRA_SERVER.getValue());

        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        String email = user.getEmail();

        MigrationConfig migrationConfig = MigrationConfig.builder()
                .email(email)
                .build();

        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
                spaceNodeTree,
                targetSpaceId,
                sourceSpaceId,
                migrationType,
                migrationConfig
        );

        // 迁移中遇到错误抛异常并终止迁移
        if (overallResult.getErrorMessage() != null) {
            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
            throw new BusinessException(overallResult.getErrorMessage());
        }

        // 迁移后的节点重新构建成树并入库
        saveNewNodeTree(spaceNodeTree, targetSpaceId, overallResult.getNodeIdMapping(), userId,
                sourceSpaceId, migrationType, migrationConfig);
        List<String> appSpaceNodeIds =  overallResult.getNodeIdMapping().values().stream().toList();
        List<SpaceNodeEntity> spaceNodeEntityList = spaceNodeQueryManager.getSpaceNodeByAppIds(appSpaceNodeIds);

        overallResult.getNodeIdMapping().forEach((k,v) -> {
            CopyFileVo vo = new  CopyFileVo();
            vo.setAppSpaceNodeId(v);
            spaceNodeEntityList.stream().filter(o -> o.getAppSpaceNodeId().equals(v)).
                    findFirst().ifPresent(spaceNodeEntity -> vo.setAioSpaceNodeId(spaceNodeEntity.getId().toString()));
            copyFileVoList.add(vo);

        });
        return copyFileVoList;
    }

    @Override
    public List<CopyFileVo> copyShareFile(List<Long> spaceNodeIds, Long userId, String targetSpaceId, String shareId) {
        // 判断用户是否对share有权限
        NodeShareEntity nodeShareEntity = nodeShareService.getByShareId(shareId);
        if (nodeShareEntity == null || Boolean.FALSE.equals(nodeShareEntity.getIsEnabled())) {
            throw new BusinessException(NodeShareException.SHARE_FORBIDDEN);
        }
        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(nodeShareEntity.getSpaceNodeId());
        if (spaceNodeEntity == null) {
            throw new BusinessException(NodeShareException.NODE_NOT_FOUND_OR_DELETED);
        }
        NodeShareProps props = NodeShareProps.fromBits(nodeShareEntity.getPropsBits());
        if (!props.getCanBeStored()) {
            throw new BusinessException(NodeShareException.NODE_SHARE_FORBID_STORE);
        }
        // todo 鉴权不太全, 未考虑指定人员分享和过期时间, 以及spaceNodeIds是否包含在shareId对应的子树里, 以后再重构
        return copyFile(spaceNodeIds, userId, spaceNodeEntity.getSpaceId(), targetSpaceId);
    }

    @Override
    public CopyVersionSnapshotVo copyVersionSnapshot(Long spaceNodeId, String snapshotName, String sourceSpaceId,
                                                     String targetSpaceId, Long userId, Integer type) {
        log.warn("spaceNodeId:{},snapshotName:{}, sourceSpaceId:{}.targetSpaceId:{},userId:{}",
                spaceNodeId, snapshotName, sourceSpaceId, targetSpaceId, userId);
        CollabspaceVersionSnapshotEntity entity = versionSnapshotService.getByName(snapshotName, spaceNodeId);
        if (entity != null){
            throw new BusinessException("副本名称重复");
        }
        // 生成spaceNodeId的副本
        Set<Long> targetNodeIds = new HashSet<>(Collections.singleton(spaceNodeId));
        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(sourceSpaceId);
        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);

        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(MigrationTypeEnum.INTRA_SERVER.getValue());

        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        String email = user.getEmail();

        MigrationConfig migrationConfig = MigrationConfig.builder()
                .email(email)
                .build();

        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
                spaceNodeTree,
                targetSpaceId,
                sourceSpaceId,
                migrationType,
                migrationConfig
        );

        // 迁移中遇到错误抛异常并终止迁移
        if (overallResult.getErrorMessage() != null) {
            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
            throw new BusinessException(overallResult.getErrorMessage());
        }

        TreeNode<SpaceNodeVo> node = spaceNodeTree.stream().filter(o -> o.getData().getId().equals(spaceNodeId)).findFirst().orElse(null);
        String snapShotId = null;
        if (node != null) {
            snapShotId = overallResult.getNodeIdMapping().get(String.valueOf(node.getData().getAppSpaceNodeId()));
        }
        if (snapShotId == null){
            throw new BusinessException("copy file error");
        }
        entity = CollabspaceVersionSnapshotEntity.builder().snapshotName(snapshotName).snapshotId(snapShotId).nodeId(spaceNodeId)
                .operatorId(0L).snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue()).build();
        versionSnapshotService.save(entity);
        // 补充spaceNode， 增加鉴权
        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
                .appSpaceNodeId(snapShotId)
                .name(snapshotName)
                .type(type)
                .description("")
                .spaceId(sourceSpaceId)
                .createdBy(userId)
                .updatedBy(userId)
                .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
                .build();

        spaceNodeService.save(spaceNodeEntity);
        return CopyVersionSnapshotVo.builder().snapshotName(snapshotName).snapShotId(snapShotId).id(entity.getId()).build();
    }

    @Override
    public void deleteVersionSnapshot(Long id) {
        CollabspaceVersionSnapshotEntity entity = versionSnapshotService.getById(id);
        if (entity == null){
            throw new BusinessException("can not find snapshot with id:" + id );
        }
        entity.setSnapshotStatus(VersionSnapshotStatusEnum.DISABLED.getValue());
        entity.setOperatorId(SessionContext.getUserId());
        versionSnapshotService.updateById(entity);

    }


    @Override
    public void recoverVersionSnapshot(Long id) {
        CollabspaceVersionSnapshotEntity entity = versionSnapshotService.getById(id);
        if (entity == null){
            throw new BusinessException("can not find snapshot with id:" + id );
        }
        entity.setSnapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue());
        entity.setOperatorId(0L);
        versionSnapshotService.updateById(entity);
    }

    @Override
    public void deleteOverTimeSnapshot() {
        // 获取全部状态是disabled 并且更新时间比当前时间大于30天的snapshot, 批量删除
        List<CollabspaceVersionSnapshotEntity> deleteList = versionSnapshotService.getOverTimeSnapshotList();
        if (!deleteList.isEmpty()){
            versionSnapshotService.removeBatchByIds(deleteList.stream().map(CollabspaceVersionSnapshotEntity::getId).toList());
        }
    }

    @Override
    public VersionSnapshotVo updateVersionSnapshot(Long id, String name) {
        CollabspaceVersionSnapshotEntity entity = versionSnapshotService.getById(id);
        if (entity == null){
            throw new BusinessException("can not find snapshot with id:" + id );
        }
        entity.setSnapshotName(name);
        versionSnapshotService.updateById(entity);
        return VersionSnapshotVo.builder().snapshotId(id.toString()).snapshotName(name).build();
    }


    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId,
                                 Map<String, String> nodeIdMapping, Long userId,
                                 String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
        if (originalTree == null || originalTree.isEmpty()) {
            log.info("No tree nodes to save for space: {}", spaceId);
            return;
        }

        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());

        for (TreeNode<SpaceNodeVo> node : originalTree) {
            Long parentId = ROOT_PARENT_ID;
            if (spaceId.equals(node.getData().getSpaceId())) {
                // 同空间站复制在原父节点下
                // todo 优化
                parentId = node.getParentId();
            }
            saveNodeAndChildren(node, spaceId, nodeIdMapping, parentId, userId,
                    sourceSpaceId, migrationType, migrationConfig);
        }

        log.info("Completed saving new node tree for space: {}", spaceId);
    }

    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
                                     Long parentId, Long userId, String sourceSpaceId,
                                     MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
        SpaceNodeVo spaceNodeVo = node.getData();
        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
        String newNodeId = nodeIdMapping.get(oldNodeId);

        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            newNodeId = "";
        }

        if (newNodeId == null) {
            log.error("No mapping found for node: {}", oldNodeId);
            return;
        }

        // todo:这里的序号没有考虑并发问题，如有需使用分布式锁
        Integer count = nodeInstancesManager.getCountByOriginId(node.getData().getId());
        String name = node.getData().getName() +  "的副本" ;
        if (count > 0){
            name = name + "(" + count + ")";
        }

        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
                .appSpaceNodeId(newNodeId)
                .name(name)
                .type(spaceNodeVo.getType())
                .description(spaceNodeVo.getDescription())
                .spaceId(spaceId)
                .createdBy(userId)
                .updatedBy(userId)
                .build();

        spaceNodeService.save(spaceNodeEntity);

        // 补充副本关系
        nodeInstancesManager.createInstance(node.getData().getId(), spaceNodeEntity.getId(), 0);
        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());

        // 复制文件关联的版本快照
        copyVersionSnapshots(node.getData().getId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);

        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
                        sourceSpaceId, migrationType, migrationConfig);
            }
        }
    }

    private void checkCopy(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId) {
        if (originalTree == null || originalTree.isEmpty()) {
            log.info("No tree nodes to save for space: {}", spaceId);
            return;
        }

        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());

        for (TreeNode<SpaceNodeVo> node : originalTree) {
            Long parentId = ROOT_PARENT_ID;
            if (spaceId.equals(node.getData().getSpaceId())) {
                parentId = node.getParentId();
            }
            checkCopyName(node, spaceId, parentId);
        }

        log.info("Completed saving new node tree for space: {}", spaceId);
    }

    private void checkCopyName(TreeNode<SpaceNodeVo> node, String spaceId, Long parentId) {

        Long spaceNodeId = node.getData().getId();

        Integer count = nodeInstancesManager.getCountByOriginId(spaceNodeId);
        String name = node.getData().getName() +  "的副本" ;
        if (count > 0){
            name = name + "(" + count + ")";
        }

        Long nodeId = node.getId();
        NodeEntity nodeEntity;
        if(null==nodeId){
            nodeEntity = nodeService.getByRelId(spaceNodeId);
            ExceptionUtil.isNotNull(nodeEntity, DatabaseException.QUERY_EMPTY_BY_ID);
        }else{
            nodeEntity = nodeService.getById(nodeId);
            ExceptionUtil.isNotNull(nodeEntity, DatabaseException.QUERY_EMPTY_BY_ID);
        }



        boolean checkResult = spaceNodeQueryManager.checkNameWithParent(spaceId, name, nodeEntity.getParentId());
        if(!checkResult) {
            throw new BusinessException(name+"已存在重名文件/文件夹");
        }


    }

    /**
     * 迁移文件时，复制其关联的历史版本快照
     */
    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
                                       String targetSpaceId, String sourceSpaceId,
                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig,
                                       Long userId) {
        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            return;
        }

        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
        if (snapshots.isEmpty()) {
            return;
        }

        log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: originalNodeId={}, newNodeId={}, snapshotCount={}",
                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());

        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
            try {
                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
                snapshotNodeVo.setName(snapshot.getSnapshotName());

                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
                snapshotTreeNode.setData(snapshotNodeVo);

                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
                snapshotTree.add(snapshotTreeNode);

                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);

                if (result.getErrorMessage() != null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed, originalNodeId={}, snapshotId={}, error={}",
                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
                    continue;
                }

                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
                if (newSnapshotFileId == null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
                    continue;
                }

                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
                        .nodeId(newSpaceNodeEntity.getId())
                        .snapshotId(newSnapshotFileId)
                        .snapshotName(snapshot.getSnapshotName())
                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
                        .operatorId(userId)
                        .build();
                versionSnapshotService.save(newSnapshot);

                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
                        .appSpaceNodeId(newSnapshotFileId)
                        .name(snapshot.getSnapshotName())
                        .type(newSpaceNodeEntity.getType())
                        .description("")
                        .spaceId(targetSpaceId)
                        .createdBy(userId)
                        .updatedBy(userId)
                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
                        .build();
                spaceNodeService.save(snapshotSpaceNode);

                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied, originalSnapshotId={}, newSnapshotId={}",
                        snapshot.getSnapshotId(), newSnapshotFileId);
            } catch (Exception e) {
                log.error("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed, originalNodeId={}, snapshotId={}, error={}",
                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
            }
        }
    }
}

