        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
        mapper.registerModule(module);
        JavaType treeNodeType =
                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
        JavaType listType =
                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
        return mapper.readValue(json, listType);
    }

